// Auth simple via Bearer Token. HTTPS protège déjà la transmission.
// TODO : passer en HMAC quand n8n autorisera 'crypto', via un node Crypto natif.
const expectedToken = 'CHANGEZ_MOI_AVEC_VOTRE_TOKEN_DE_32_OCTETS_BASE64URL';

const raw = $input.first().json;
const body = raw.body || raw;
const headers = raw.headers || {};
const authHeader = headers['authorization'] || headers['Authorization'] || '';
const userIdHeader = headers['x-jarvis-user'] || 'unknown';

const providedToken = authHeader.replace(/^Bearer\s+/i, '').trim();
const valid = providedToken === expectedToken;

if (valid) {
  return [{ json: {
    status: 'ok',
    user_id: userIdHeader,
    received: body,
    jarvis_says: 'Bien Monsieur. Ce sera fait.',
    note: 'Mock — forward vers backend Jarvis local à ajouter quand Cloudflare Tunnel sera prêt.',
    timestamp: new Date().toISOString()
  }}];
}

return [{ json: {
  status: 'unauthorized',
  reason: !authHeader ? 'header Authorization manquant' : 'token invalide',
  timestamp: new Date().toISOString()
}}];
